head.script:
//==================================================================================================================
// id       : op_302_01_27b
// 이름     : 컨테이너반입신고
// 경로     : 물류/작업실적/EDI/세관/컨테이너반입신고
// 작 성 자 : 최지수
// 작 업 일 : 2026-04-09
//==================================================================================================================
//현재일자
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");

//-------------------------------------------------------------------------
// 공통: 체크된 행의 반입일시 14자리 패딩 
//-------------------------------------------------------------------------
scwin.f_padCrryinoutDtm = function () {
    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            var dtm = ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm");
            if (dtm.length < 14) {
                dtm = dtm + "00000000000000".substring(0, 14 - dtm.length);
                ds_cntrInDeclarInfo.setCellData(i, "crryinoutDtm", dtm);
            }
        }
    }
};

//-------------------------------------------------------------------------
// 공통: 체크된 행의 반입일시/반입유형/사고유형 필수값 검증
//-------------------------------------------------------------------------
scwin.f_validateCheckedRows = function () {
    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm") == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["반입일시"]);
                return false;
            }
            if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutPatternCd") == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["반입유형코드"]);
                return false;
            }
            if (ds_cntrInDeclarInfo.getCellData(i, "accdPatternCd") == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["사고유형코드"]);
                return false;
            }
            if (ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm").length < 14) {
                $c.gus.cfAlertMsg("반입일시는 년/월/일/시/분/초 까지 입력하셔야 합니다.");
                return false;
            }
            // 날짜 유효성 검증 (ASIS covDateValidator 대응)
            if (!scwin.f_isValidDateTime(ds_cntrInDeclarInfo.getCellData(i, "crryinoutDtm"))) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["반입일시"]);
                return false;
            }
        }
    }
    return true;
};

/* 날짜시간 유효성 검증 (YYYYMMDDHHmmss) */
scwin.f_isValidDateTime = function (val) {
    if (!val || val.length != 14) return false;
    var y = parseInt(val.substring(0, 4), 10);
    var m = parseInt(val.substring(4, 6), 10);
    var d = parseInt(val.substring(6, 8), 10);
    var hh = parseInt(val.substring(8, 10), 10);
    var mm = parseInt(val.substring(10, 12), 10);
    var ss = parseInt(val.substring(12, 14), 10);
    if (m < 1 || m > 12) return false;
    if (d < 1 || d > 31) return false;
    if (hh < 0 || hh > 23) return false;
    if (mm < 0 || mm > 59) return false;
    if (ss < 0 || ss > 59) return false;
    var dt = new Date(y, m - 1, d);
    if (dt.getFullYear() != y || dt.getMonth() != m - 1 || dt.getDate() != d) return false;
    return true;
};

//-------------------------------------------------------------------------
// 공통: 작업장 유효성 검증
//-------------------------------------------------------------------------
scwin.f_isValidWrkPl = function () {
    for (var i = 0; i < ds_wrkPlCd.getRowCount(); i++) {
        if (ds_wrkPlCd.getCellData(i, "cd") == dma_condition.get("wrkPlCd")) {
            return true;
        }
    }
    return false;
};

scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "OP133", compID: "gr_cntrInDeclarInfo:crryinoutPatternCd", opt: { "range": "1" } },
        { grpCd: "OP132", compID: "gr_cntrInDeclarInfo:accdPatternCd", opt: { "range": "1" } }
    ];

    $c.data.setCommonCode(codeOptions);

    ed_msn.setValue("");
    ed_hsn.setValue("");

    dma_condition.set("crryinoutClsCd", "I");

    $c.gus.cfDisableBtn([btn_Save, btn_Trans, btn_Delete]);

    dma_wrkPlCd.set("grpCd", "SD151");
    dma_wrkPlCd.set("cd", "");
    dma_wrkPlCd.set("cdNm", "");
    $c.sbm.execute(sbm_wrkPlCd);
};

scwin.onUdcCompleted = function () {
    ed_crryinoutDtmFrom.setValue(scwin.strToDate);
    ed_crryinoutDtmTo.setValue(scwin.strToDate);
    ed_wrkPlCd.focus();
};



//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([tb_searchCondition])) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_crryinoutDtmFrom.getValue(), ed_crryinoutDtmTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_crryinoutDtmFrom.focus();
        return;
    }

    if (declar_chk.getValue() == "1") {
        if (ed_cntrNo.getValue() == "" && ed_mrn.getValue() == "") {
            $c.gus.cfAlertMsg("컨테이너,화물관리번호 중 하나는 입력해 주세요.");
            return false;
        }
    }

    if (declar_chk.getValue() == "1") {
        dma_condition.set("declarTrgtYn", 1);
    } else {
        dma_condition.set("declarTrgtYn", 0);
    }

    $c.sbm.execute(sbm_Retrieve);

};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(search_cond, null);
    ed_crryinoutDtmFrom.setValue(scwin.strToDate);
    ed_crryinoutDtmTo.setValue(scwin.strToDate);
};

//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.f_Trans = async function () {
    var count = 0;

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") == "4") {
            $c.gus.cfAlertMsg("전송구분이 전송제외인 경우에는 전송을 하실수가 없습니다.");
            ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1
            && (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송대기" ||
                ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료")) {
            $c.gus.cfAlertMsg("전송중에는 재전송을 하실수가 없습니다.");
            ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            ds_cntrInDeclarInfo.setCellData(i, "wrkPlCd", ed_wrkPlCd.getValue());
            count++;
        }
    }

    scwin.f_padCrryinoutDtm();

    if (!scwin.f_validateCheckedRows()) {
        return false;
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 자료 전송이 불가능한 작업장입니다.");
        return false;
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("전송할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    if (await $c.win.confirm("전송하시겠습니까?")) {
        $c.sbm.execute(sbm_trans);
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    var count = 0;

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1 && (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료"
            || ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == ""
            || ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") == "4")) {
            $c.gus.cfAlertMsg("전송구분이 전송완료/전송제외인 경우에는 저장을 하실수가 없습니다.");
            ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            count++;
        }
    }

    scwin.f_padCrryinoutDtm();

    if (!scwin.f_validateCheckedRows()) {
        return false;
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 컨테이너 반입신고를 할 수 없는 작업장입니다.");
        return false;
    }

    dma_condition.set("delYn", 0);

    if (declar_chk.getValue() == "1") {
        for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
            if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
                ds_cntrInDeclarInfo.setCellData(i, "rowStatus", "U");
            }
        }
    }

    if (ds_cntrInDeclarInfo.getModifiedIndex().length === 0) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("저장할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {debugger;
    var count = 0;

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            count++;
        }
    }

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1
            && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") != "3"
            && ds_cntrInDeclarInfo.getCellData(i, "sndClsCd") != "4") {
            $c.gus.cfAlertMsg("삭제는 전송구분이 미전송/전송제외인 경우에만 가능합니다.");
            ds_cntrInDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 자료 삭제가 불가능한 작업장입니다.");
        return false;
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("삭제할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "chk") == 1) {
            dma_condition.set("delYn", 1);
            ds_cntrInDeclarInfo.modifyRowStatus(i, "D");
        }
    }

    if (await $c.win.confirm("삭제하시겠습니까?")) {
        $c.sbm.execute(sbm_delete);
    }
};


//-------------------------------------------------------------------------
// 오류 상세내역 조회 팝업
//-------------------------------------------------------------------------
scwin.f_errorPopUp = function (row) {
    //컨테이너 반입 오류시에도 오류상세내역 확인가능하게 수정
    var docCd = "";

    if (ds_cntrInDeclarInfo.getCellData(row, 'crryinoutPatternCd') == '19') {
        docCd = "355";
    } else {
        docCd = "5LA";
    }

    var declarNo = ds_cntrInDeclarInfo.getCellData(row, "crryinoutDeclarNo");
    var deg = 0;

    let data = {
        deg: deg,
        docCd: docCd,
        declarNo: declarNo
    };

    let opts = {
        id: "smpPop",
        popupName: "",
        modal: false,
        type: "browserPopup",
        width: 860,
        height: 580,
        title: ""
    };

    $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);

};

//-------------------------------------------------------------------------
//  전송구분에 따른 Total 
//-------------------------------------------------------------------------
scwin.f_sndClsTotal = function () {
    var v_send = 0;//전송 
    var v_unSend = 0;//미전송
    var v_acpt = 0;//접수 
    var v_error = 0;//오류 
    var v_transComplete = 0; //전송완료
    var v_forceAcpt = 0; //강제접수

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송")
            v_send++;

        else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "미전송")
            v_unSend++;

        else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "접수")
            v_acpt++;

        else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "오류")
            v_error++;

        else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "전송완료")
            v_transComplete++;

        else if (ds_cntrInDeclarInfo.getCellData(i, "sndClsNm") == "강제접수")
            v_forceAcpt++;
    }

    send.setValue(v_send);
    unSend.setValue(v_unSend);
    acpt.setValue(v_acpt);
    error.setValue(v_error);
    transComplete.setValue(v_transComplete);
    forceAcpt.setValue(v_forceAcpt);
};

//-------------------------------------------------------------------------
// 강제접수
//-------------------------------------------------------------------------
scwin.f_forcedReceipt = async function () {
    if (await $c.win.confirm("강제접수처리 하시겠습니까?")) {
        $c.sbm.execute(sbm_forcedReceipt);
    }
};

//////////////////////////////////////// S U B M I S S I O N    E V E N T //////////////////////////////////


//조회
scwin.sbm_Retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
        return;
    }

    grp_totalArea.setStyle("visibility", "visible");

    if (ds_cntrInDeclarInfo.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    }

    totalRows.setValue(ds_cntrInDeclarInfo.getRowCount());

    scwin.f_sndClsTotal();//전송 구분 별 Total

    for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
        if (declar_chk.getValue() == "1") {
            if (ds_cntrInDeclarInfo.getCellData(i, "dsmbrkBondZoneCd") == ds_cntrInDeclarInfo.getCellData(i, "bondZoneCd")) {
                ds_cntrInDeclarInfo.setCellData(i, "crryinoutPatternCd", "10");
            }
        }
        if (ds_cntrInDeclarInfo.getCellData(i, "accdPatternCd") == "") {
            ds_cntrInDeclarInfo.setCellData(i, "accdPatternCd", "OKY");
        }

        //경과일 폰트색 변경 (선조회 모드가 아닐 때만 적용)
        if (declar_chk.getValue() != "1") {
            if (Number(ds_cntrInDeclarInfo.getCellData(i, "arrowDt")) >= 3) {
                gr_cntrInDeclarInfo.setCellStyle(i, "arrowDt", "color", "red");
            } else {
                gr_cntrInDeclarInfo.setCellStyle(i, "arrowDt", "color", "black");
            }
        }
    }

    //전송구분이 오류이면 반입신고번호 폰트 변경
    for (var j = 0; j < ds_cntrInDeclarInfo.getRowCount(); j++) {
        if (ds_cntrInDeclarInfo.getCellData(j, "sndClsNm") == "오류") {
            gr_cntrInDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "textDecoration", "underline");
            gr_cntrInDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "cursor", "pointer");
        }
    }

    if (declar_chk.getValue() == "1") {
        $c.gus.cfDisableBtn([btn_Trans, btn_Delete]);
    } else {
        $c.gus.cfEnableObjects([btn_forced, btn_Save, btn_Trans, btn_Delete]);
    }

    ds_cntrInDeclarInfo.modifyAllStatus("R");
};

//전송
scwin.sbm_trans_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.win.alert(e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
        return;
    }
    await $c.win.alert("성공적으로 전송하였습니다.");
    dma_condition.set("delYn", 0);
    scwin.f_Retrieve();
};

//저장
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.win.alert(e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
        return;
    }
    await $c.win.alert(MSG_CM_INF_001);
    $c.gus.cfEnableObjects([btn_Trans]);
    scwin.f_Retrieve();
};

//삭제
scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.win.alert(e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
        return;
    }
    await $c.win.alert(MSG_CM_INF_004);
    dma_condition.set("delYn", 0);
    scwin.f_Retrieve();
};

scwin.sbm_forcedReceipt_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.win.alert(e.responseJSON.resultDataSet[0].Msg || "오류가 발생했습니다.");
        return;
    }
    await $c.win.alert("성공적으로 수정하였습니다.");
    $c.sbm.execute(sbm_Retrieve);
};

scwin.sbm_wrkPlCd_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        console.error("sbm_wrkPlCd 에러:", e.responseJSON.resultDataSet[0].Msg);
        return;
    }
};

//////////////////////////////////////// C O M P O N E N T   E V E N T //////////////////////////////////

scwin.declar_chk_onchange = function (info) {
    if (declar_chk.getValue() == "1") {
        $c.gus.cfDisableBtn([btn_Trans, btn_Delete]);

    } else {
        $c.gus.cfEnableObjects([btn_Save, btn_Delete]);
    }
};

//OnCloseUp
scwin.gr_cntrInDeclarInfo_oneditend = function (rowIndex, columnIndex, value) {
    var v_mrn = ed_mrn.getValue();
    var v_msn = ed_msn.getValue();
    var v_hsn = ed_hsn.getValue();
    if ($c.gus.cfIsNull(v_hsn)) {
        v_hsn = "0";
    }

    let colid = gr_cntrInDeclarInfo.getColumnID(columnIndex);

    if (colid == "crryinoutPatternCd") {
        for (var i = rowIndex + 1; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
            if (ds_cntrInDeclarInfo.getCellData(i, "mrn") == v_mrn
                && ds_cntrInDeclarInfo.getCellData(i, "msn") == v_msn
                && ds_cntrInDeclarInfo.getCellData(i, "hsn") == v_hsn) {
                ds_cntrInDeclarInfo.setCellData(i, "crryinoutPatternCd", ds_cntrInDeclarInfo.getCellData(rowIndex, "crryinoutPatternCd"));
            }
        }
    }
};

scwin.gr_cntrInDeclarInfo_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    let colid = gr_cntrInDeclarInfo.getColumnID(columnIndex);

    if (colid == "crryinoutDeclarNo") {
        if (ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") == "오류") {
            scwin.f_errorPopUp(rowIndex);
        }
    }

    if (colid == "chk") {
        if (ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "3"
            && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != "오류"
            && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != "전송완료"
            && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsNm") != ""
            && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "4"
            && ds_cntrInDeclarInfo.getCellData(rowIndex, "sndClsCd") != "5") {
            $c.gus.cfAlertMsg("전송구분이 전송완료/미전송/전송제외/오류/필수항목오류인 경우에만 선택하실수 있습니다.");
            ds_cntrInDeclarInfo.setCellData(rowIndex, "chk", 0);
            return false;
        }

        //같은 컨테이너번호 행 연동 체크
        for (var i = 0; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
            if (ds_cntrInDeclarInfo.getCellData(rowIndex, "chk") == 1 &&
                ds_cntrInDeclarInfo.getCellData(rowIndex, "cntrNo") == ds_cntrInDeclarInfo.getCellData(i, "cntrNo")) {
                ds_cntrInDeclarInfo.setCellData(i, "chk", 1);
            }
        }
    }
};

//OnExit
scwin.gr_cntrInDeclarInfo_onafteredit = function (rowIndex, columnIndex, value) {
    var v_mrn = ed_mrn.getValue();
    var v_msn = ed_msn.getValue();
    var v_hsn = ed_hsn.getValue();
    if ($c.gus.cfIsNull(v_hsn)) v_hsn = "0";

    let colid = gr_cntrInDeclarInfo.getColumnID(columnIndex);

    if (colid == "crryinoutBasisNo") {
        for (var i = rowIndex + 1; i < ds_cntrInDeclarInfo.getRowCount(); i++) {
            if (ds_cntrInDeclarInfo.getCellData(i, "mrn") == v_mrn
                && ds_cntrInDeclarInfo.getCellData(i, "msn") == v_msn
                && ds_cntrInDeclarInfo.getCellData(i, "hsn") == v_hsn) {
                ds_cntrInDeclarInfo.setCellData(i, "crryinoutBasisNo", ds_cntrInDeclarInfo.getCellData(rowIndex, "crryinoutBasisNo"));
            }
        }
    }
};



